questionvariables.text:
/* Q5: 5G Link Budget Calculation */
idx: 1 + rand(5);

/* Parameter sets */
f_GHz_list: [3.5, 5, 28, 28, 39];
r_m_list: [100, 200, 50, 100, 50];
P_t_list: [30, 33, 27, 30, 27];
G_t_list: [15, 15, 25, 25, 30];
G_r_list: [3, 5, 5, 5, 8];

f_GHz: f_GHz_list[idx];
r_m: r_m_list[idx];
P_t: P_t_list[idx];
G_t: G_t_list[idx];
G_r: G_r_list[idx];

/* Constants */
c0: 3*10^8;

/* Derived */
f_Hz: f_GHz * 10^9;

/* (a) Wavelength */
lambda_val: float(c0 / f_Hz);
tans1: lambda_val;

/* (b) FSPL in dB */
FSPL_val: float(20 * log(4*%pi*r_m/lambda_val) / log(10));
tans2: FSPL_val;

/* (c) Received power in dBm */
Pr_val: float(P_t + G_t + G_r - FSPL_val);
tans3: Pr_val;

/* (d) Change when distance doubles: always -6.02 dB */
delta_Pr: float(-20 * log(2) / log(10));
tans4: delta_Pr;

/* (e) Module classification MCQ */
/* Correct: All four modules (M1+M2+M3+M4) */
ta5: random_permutation([
  [1, true, "All four modules (M1 + M2 + M3 + M4)"],
  [2, false, "Only M4 (Waves/Radiation)"],
  [3, false, "M1 + M4 (Circuits + Waves)"],
  [4, false, "M3 + M4 (Magnetics + Waves)"]
]);

/* Error model values */
/* E1: used 10*log10 instead of 20*log10 for FSPL */
FSPL_err: float(10 * log(4*%pi*r_m/lambda_val) / log(10));
/* E2: added FSPL instead of subtracting */
Pr_err_add: float(P_t + G_t + G_r + FSPL_val);
/* E3: doubling distance gives -3 dB instead of -6 dB */
delta_err: -3;

/* (f) Frequency effect on path loss MCQ */
ta6: random_permutation([
  [1, true, "Decreases — higher frequency means shorter wavelength and higher path loss"],
  [2, false, "Increases — higher frequency waves carry more energy"],
  [3, false, "Stays the same — frequency does not affect path loss"],
  [4, false, "Depends on whether the antennas are recalibrated"]
]);
correct_f: 1;

/* (g) Link margin — received power above sensitivity threshold */
sensitivity: if is(f_GHz <= 6) then -90 else -70;
link_margin_val: float(Pr_val - sensitivity);
tans6: link_margin_val;
